CodeInjections.CodeInjection:
// No need to apply depth correction and apply a small offset from all the way to far plane to avoid issues with imprecise position interpolation
#undef TRANSFORM_VS_DEPTH_OUTPUT
Out.position.z = Out.position.w - 0.1;

sampler2D sunsetTexture;
sampler2D nightTexture;
sampler2D sunriseTexture;
sampler2D rainDayTexture;
sampler2D rainNightTexture;

#if defined(USE_SKYBOX)
float3 emissiveColorSunset = tex2D(sunsetTexture, In.vs.ALBEDOMAP_TEXCOORD).xyz;
float3 emissiveColorNight = tex2D(nightTexture, In.vs.ALBEDOMAP_TEXCOORD).xyz;
float3 emissiveColorSunrise = tex2D(sunriseTexture, In.vs.ALBEDOMAP_TEXCOORD).xyz;
float3 emissiveColorRainDay = tex2D(rainDayTexture, In.vs.ALBEDOMAP_TEXCOORD).xyz;
float3 emissiveColorRainNight = tex2D(rainNightTexture, In.vs.ALBEDOMAP_TEXCOORD).xyz;
emissiveColor.xyz = emissiveColor.xyz*partScale.x + emissiveColorSunset.xyz*partScale.y + emissiveColorNight.xyz*partScale.z + emissiveColorSunrise.xyz*partScale.w + emissiveColorRainDay*rainScale.x + emissiveColorRainNight*rainScale.y;
#endif

{
#if defined(ADD_FOG) && (defined(FOG_EXTINCTION) || defined(FOG_INSCATTERING))

    float heightNorm = -normalize(In.vs.vertToEyeVector).y;
    float distance = lerp(3000, 200, saturate(heightNorm));
    #if defined(GS_LOW_SPEC_FOG)
        float extinction = exp(-expFogDensity*distance);
        return lerp(expFogColor*translucentLightingScale, oColor.xyz, extinction);
    #else
        return applyFogLightScattering(distance, oColor.xyz, translucentLightingScale, scatteringDirLightDirection, viewDir, lightColorAtGround, fogRayleighExtinctionCoeff, fogMieExtinctionCoeff);
    #endif

#endif
}
